import React, { useId } from 'react';
import { Card, CardContent, Box, Typography, Stack } from '@mui/material';
import { ResponsiveChartContainer, LinePlot, ChartsXAxis, ChartsYAxis, ChartsClipPath } from '@mui/x-charts';
import response from './response.json';

interface SchedulePreview {
  time: string;
  targetTemp: number;
}

interface ThermostatData {
  currentTemperature: number;
  targetTemperature: number;
  schedulePreview: SchedulePreview[];
}

interface MetaData {
  theme: string;
  dataMode: string;
  layout: string;
  primaryColor: string;
  accentColor: string;
}

export default function Widget() {
  const data = response.data as ThermostatData;
  const meta = response.meta as MetaData;
  const clipPathId = useId();

  return (
    <Card
      sx={{
        width: 'fit-content',
        minWidth: 320,
        maxWidth: 450,
        bgcolor: meta.theme === 'light' ? '#FFFFFF' : '#1E1E1E',
        color: meta.theme === 'light' ? '#000000' : '#FFFFFF',
      }}
      elevation={2}
    >
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" fontWeight={600}>
              Home Thermostat
            </Typography>
            <Typography variant="body1" color="text.secondary" sx={{ mb: 0.5 }}>
              Current Temperature: {data.currentTemperature}°F
            </Typography>
            <Typography variant="body1" color="text.secondary">
              Target Temperature: {data.targetTemperature}°F
            </Typography>
          </Box>

          <Box sx={{ width: '100%', height: 200 }}>
            <ResponsiveChartContainer
              series={[
                {
                  type: 'line',
                  data: data.schedulePreview.map(p => p.targetTemp),
                  color: meta.primaryColor,
                  label: 'Target Temp',
                  curve: 'linear',
                },
              ]}
              xAxis={[
                {
                  scaleType: 'band',
                  data: data.schedulePreview.map(p => p.time),
                  id: 'time',
                },
              ]}
              yAxis={[{ id: 'temperature', label: 'Temp (°F)' }]}
            >
              <g clipPath={`url(#${clipPathId})`}>
                <LinePlot />
              </g>
              <ChartsXAxis
                axisId="time"
                tickLabelStyle={{ fontSize: 10, fill: meta.theme === 'light' ? '#000000' : '#FFFFFF' }}
              />
              <ChartsYAxis
                axisId="temperature"
                tickLabelStyle={{ fontSize: 10, fill: meta.theme === 'light' ? '#000000' : '#FFFFFF' }}
              />
              <ChartsClipPath id={clipPathId} />
            </ResponsiveChartContainer>
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
